import{_ as n,c as a,o as p,ag as e}from"./chunks/framework.ELrfyV9R.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2025/2025-12-25-youtobe视频转录.md","filePath":"ai/2025/2025-12-25-youtobe视频转录.md","lastUpdated":1773928509000}'),l={name:"ai/2025/2025-12-25-youtobe视频转录.md"};function i(t,s,c,o,r,u){return p(),a("div",null,s[0]||(s[0]=[e(`<h2 id="将-youtube-视频-通过-url-或上传的本地视频转录为带有说话人标签和时间戳的结构化格式文本。" tabindex="-1">将 YouTube 视频（通过 URL）或上传的本地视频转录为带有说话人标签和时间戳的结构化格式文本。 <a class="header-anchor" href="#将-youtube-视频-通过-url-或上传的本地视频转录为带有说话人标签和时间戳的结构化格式文本。" aria-label="Permalink to &quot;将 YouTube 视频（通过 URL）或上传的本地视频转录为带有说话人标签和时间戳的结构化格式文本。&quot;">​</a></h2><ul><li><a href="https://x.com/dotey/status/1971810075867046131" target="_blank" rel="noreferrer">https://x.com/dotey/status/1971810075867046131</a></li><li></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--- Prompt Start ---</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Role</span></span>
<span class="line"><span>You are an expert transcript specialist. Your task is to create a perfectly structured, verbatim transcript of a video.</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Objective</span></span>
<span class="line"><span>Produce a single, cohesive output containing the parts in this order:</span></span>
<span class="line"><span>1.  A Video Title</span></span>
<span class="line"><span>2.  A **Table of Contents (ToC)**</span></span>
<span class="line"><span>3.  The **full, chapter-segmented transcript**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* Use the same language as the transcription for the Title and ToC.</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Critical Instructions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 1. Transcription Fidelity: Verbatim &amp; Untranslated</span></span>
<span class="line"><span>* Transcribe every spoken word exactly as you hear it, including filler words (\`um\`, \`uh\`, \`like\`) and stutters.</span></span>
<span class="line"><span>* **NEVER translate.** If the audio is in Chinese, transcribe in Chinese. If it mixes languages (e.g., &quot;这个 feature 很酷&quot;), your transcript must replicate that mix exactly.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 2. Speaker Identification</span></span>
<span class="line"><span>* **Priority 1: Use metadata.** Analyze the video&#39;s title and description first to identify and match speaker names.</span></span>
<span class="line"><span>* **Priority 2: Use audio content.** If names are not in the metadata, listen for introductions or how speakers address each other.</span></span>
<span class="line"><span>* **Fallback:** If a name remains unknown, use a generic but consistent label (\`**Speaker 1:**\`, \`**Host:**\`, etc.).</span></span>
<span class="line"><span>* **Consistency is key:** If a speaker&#39;s name is revealed later, you must go back and update all previous labels for that speaker.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 3. Chapter Generation Strategy</span></span>
<span class="line"><span>* **For YouTube Links:** First, check if the video description contains a list of chapters. If so, use that as the primary basis for segmenting the transcript.</span></span>
<span class="line"><span>* **For all other videos (or if no chapters exist on YouTube):** Create chapters based on significant shifts in topic or conversation flow.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 4. Output Structure &amp; Formatting</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **Timestamp Format**</span></span>
<span class="line"><span>* All timestamps throughout the entire output MUST use the exact \`[HH:MM:SS]\` format (e.g., \`[00:01:23]\`). Milliseconds are forbidden.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **Table of Contents (ToC)**</span></span>
<span class="line"><span>* Must be the very first thing in your output, under a \`## Table of Contents\` heading.</span></span>
<span class="line"><span>* Format for each entry: \`* [HH:MM:SS] Chapter Title\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **Chapters**</span></span>
<span class="line"><span>* Start each chapter with a heading in this format: \`## [HH:MM:SS] Chapter Title\`</span></span>
<span class="line"><span>* Use two blank lines to separate the end of one chapter from the heading of the next.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **Dialogue Paragraphs (VERY IMPORTANT)**</span></span>
<span class="line"><span>* **Speaker Turns:** The first paragraph of a speaker&#39;s turn must begin with \`**Speaker Name:** \`.</span></span>
<span class="line"><span>* **Paragraph Splitting:** For a long continuous block of speech from a single speaker, split it into smaller, logical paragraphs (roughly 2-4 sentences). Separate these paragraphs with a single blank line. Subsequent consecutive paragraphs from the *same speaker* should NOT repeat the \`**Speaker Name:** \` label.</span></span>
<span class="line"><span>* **Timestamp Rule:** Every single paragraph MUST end with exactly one timestamp. The timestamp must be placed at the very end of the paragraph&#39;s text.</span></span>
<span class="line"><span>* ❌ **WRONG:** \`**Host:** Welcome back. [00:00:01] Today we have a guest. [00:00:02]\`</span></span>
<span class="line"><span>* ❌ **WRONG:** \`**Jane Doe:** The study is complex. We tracked two groups over five years to see the effects. [00:00:18] And the results were surprising.\`</span></span>
<span class="line"><span>* ✅ **CORRECT:** \`**Host:** Welcome back. Today we have a guest. [00:00:02]\`</span></span>
<span class="line"><span>* ✅ **CORRECT (for a long monologue):**</span></span>
<span class="line"><span>\`**Jane Doe:** The study is complex. We tracked two groups over a five-year period to see the long-term effects. [00:00:18]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>And the results, well, they were quite surprising to the entire team. [00:00:22]\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **Non-Speech Audio**</span></span>
<span class="line"><span>* Describe significant sounds like \`[Laughter]\` or \`[Music starts]\`, each on its own line with its own timestamp: \`[Event description] [HH:MM:SS]\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>### Example of Correct Output</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Table of Contents</span></span>
<span class="line"><span>* [00:00:00] Introduction and Welcome</span></span>
<span class="line"><span>* [00:00:12] Overview of the New Research</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## [00:00:00] Introduction and Welcome</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Host:** Welcome back to the show. Today, we have a, uh, very special guest, Jane Doe. [00:00:01]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Jane Doe:** Thank you for having me. I&#39;m excited to be here and discuss the findings. [00:00:05]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## [00:00:12] Overview of the New Research</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Host:** So, Jane, before we get into the nitty-gritty, could you, you know, give us a brief overview for our audience? [00:00:14]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Jane Doe:** Of course. The study focuses on the long-term effects of specific dietary changes. It&#39;s a bit complicated but essentially we tracked two large groups over a five-year period. [00:00:21]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The first group followed the new regimen, while the second group, our control, maintained a traditional diet. This allowed us to isolate variables effectively. [00:00:28]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Laughter] [00:00:29]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Host:** Fascinating. And what did you find? [00:00:31]</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>Begin transcription now. Adhere to all rules with absolute precision.</span></span></code></pre></div><h2 id="中文版本" tabindex="-1">中文版本 <a class="header-anchor" href="#中文版本" aria-label="Permalink to &quot;中文版本&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一位专业的转录专家。你的任务是创建一个结构完美、逐字逐句的视频转录文本。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 目标</span></span>
<span class="line"><span>生成一个单一、连贯的输出，按以下顺序包含这些部分：</span></span>
<span class="line"><span>1. 视频标题</span></span>
<span class="line"><span>2. **目录 (ToC)**</span></span>
<span class="line"><span>3. **完整的、按章节分段的转录文本**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* 标题和目录使用与转录文本相同的语言。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 关键指令</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 1. 转录准确性：逐字逐句且不翻译</span></span>
<span class="line"><span>* 准确转录每一个说出的词，包括填充词（\`嗯\`、\`呃\`、\`就是\`）和口吃。</span></span>
<span class="line"><span>* **绝不翻译。** 如果音频是中文，就转录成中文。如果混合使用多种语言（例如，&quot;这个 feature 很酷&quot;），你的转录必须准确复制这种混合。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 2. 说话人识别</span></span>
<span class="line"><span>* **优先级1：使用元数据。** 首先分析视频的标题和描述，以识别和匹配说话人姓名。</span></span>
<span class="line"><span>* **优先级2：使用音频内容。** 如果元数据中没有姓名，请听取介绍或说话人如何互相称呼。</span></span>
<span class="line"><span>* **备选方案：** 如果说话人姓名仍然未知，使用通用但一致的标签（\`**说话人1:**\`、\`**主持人:**\` 等）。</span></span>
<span class="line"><span>* **一致性是关键：** 如果说话人的姓名在后面被揭示，你必须返回并更新该说话人之前的所有标签。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 3. 章节生成策略</span></span>
<span class="line"><span>* **对于 YouTube 链接：** 首先检查视频描述是否包含章节列表。如果有，将其作为分割转录文本的主要依据。</span></span>
<span class="line"><span>* **对于所有其他视频（或如果 YouTube 上没有章节）：** 根据话题或对话流程的重大转变创建章节。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 4. 输出结构与格式</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **时间戳格式**</span></span>
<span class="line"><span>* 整个输出中的所有时间戳必须使用精确的 \`[HH:MM:SS]\` 格式（例如，\`[00:01:23]\`）。禁止使用毫秒。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **目录 (ToC)**</span></span>
<span class="line"><span>* 必须是输出的第一部分，位于 \`## 目录\` 标题下。</span></span>
<span class="line"><span>* 每个条目的格式：\`* [HH:MM:SS] 章节标题\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **章节**</span></span>
<span class="line"><span>* 每个章节以以下格式的标题开始：\`## [HH:MM:SS] 章节标题\`</span></span>
<span class="line"><span>* 使用两个空行来分隔一个章节的结尾和下一个章节的标题。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **对话段落（非常重要）**</span></span>
<span class="line"><span>* **说话人轮次：** 说话人发言的第一段必须以 \`**说话人姓名:** \` 开头。</span></span>
<span class="line"><span>* **段落分割：** 对于单个说话人的长篇连续讲话，将其分割成更小的、合乎逻辑的段落（大约2-4句话）。用一个空行分隔这些段落。来自*同一说话人*的后续连续段落不应重复 \`**说话人姓名:** \` 标签。</span></span>
<span class="line"><span>* **时间戳规则：** 每个段落必须以恰好一个时间戳结束。时间戳必须放在段落文本的最末尾。</span></span>
<span class="line"><span>* ❌ **错误示例：** \`**主持人:** 欢迎回来。[00:00:01] 今天我们有一位嘉宾。[00:00:02]\`</span></span>
<span class="line"><span>* ❌ **错误示例：** \`**张三:** 这项研究很复杂。我们追踪了两组人群五年时间来观察效果。[00:00:18] 结果令人惊讶。\`</span></span>
<span class="line"><span>* ✅ **正确示例：** \`**主持人:** 欢迎回来。今天我们有一位嘉宾。[00:00:02]\`</span></span>
<span class="line"><span>* ✅ **正确示例（长篇独白）：**</span></span>
<span class="line"><span>\`**张三:** 这项研究很复杂。我们追踪了两组人群长达五年的时间，以观察长期效果。[00:00:18]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>而结果呢，确实让整个团队都感到非常惊讶。[00:00:22]\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **非语音音频**</span></span>
<span class="line"><span>* 描述重要的声音，如 \`[笑声]\` 或 \`[音乐响起]\`，每个描述单独成行，并附上自己的时间戳：\`[事件描述] [HH:MM:SS]\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>### 正确输出示例</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 目录</span></span>
<span class="line"><span>* [00:00:00] 介绍和欢迎</span></span>
<span class="line"><span>* [00:00:12] 新研究概述</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## [00:00:00] 介绍和欢迎</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**主持人:** 欢迎回到节目。今天，我们有一位，嗯，非常特别的嘉宾，张三。[00:00:01]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**张三:** 感谢邀请我。我很高兴能来这里讨论研究发现。[00:00:05]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## [00:00:12] 新研究概述</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**主持人:** 那么，张三，在我们深入细节之前，你能，你知道的，给我们的观众做一个简要概述吗？[00:00:14]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**张三:** 当然可以。这项研究关注特定饮食变化的长期影响。这有点复杂，但本质上我们追踪了两个大型群体长达五年时间。[00:00:21]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第一组遵循新的饮食方案，而第二组，我们的对照组，保持传统饮食。这使我们能够有效地隔离变量。[00:00:28]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[笑声] [00:00:29]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**主持人:** 太有意思了。那你们发现了什么？[00:00:31]</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>现在开始转录。请绝对精确地遵守所有规则。</span></span></code></pre></div>`,5)]))}const f=n(l,[["render",i]]);export{d as __pageData,f as default};
